CodeIgniter设计验证登录
需求为在登录时验证账户是邮箱地址还是账户名，同时验证账户密码长度以及是否存在资料库中。

1. 登录界面设计从DeskApp里面直接复制对应的html代码即可，同时需要注意这个在于将HTML进行切割成不同的layout 部分。这样方便后面的复用。针对页首页脚侧边栏等采用&lt;?= include(&#39;inc/footer.php&#39;); ?&gt;)方式来引用。 而对于要传入的内容则使用 &lt;?= $this-&gt;renderSection(&#39;content&#39;); ?&gt; ，在具体的页面里使用extend扩展其他页面，而section则传入相应的值。
&lt;?= $this-&gt;extend(&#x27;backend/layout/auth-layout&#x27;)?&gt;&lt;?= $this-&gt;section(&#x27;content&#x27;); ?&gt;Auth page content here .........&lt;?= $this-&gt;endSection();?&gt;

2. 控制器设置在admin group下面增加login的get 和Post方法的控制器。分别用于打开login界面和提交登录系统。

$routes-&gt;view()可以直接展示view界面，而不用控制器中转。
使用[&#39;as&#39;=&gt;&#39;admin.handler&#39;]可以设置别名，方便在view界面进行控制，使用范例&lt;form action=&quot;&lt;?= route_to(&#39;admin.login.handler&#39;) ?&gt; &quot; method=&quot;POST&quot;&gt;

$routes-&gt;group(&#x27;admin&#x27;,static function($routes)&#123;        $routes-&gt;group(&#x27;&#x27;,[],static function($routes)&#123;            $routes-&gt;get(&#x27;home&#x27;,&#x27;AdminController::index&#x27;,[&#x27;as&#x27;=&gt;&#x27;admin.home&#x27;]);            $routes-&gt;get(&#x27;logout&#x27;,&#x27;AdminController::logoutHandler&#x27;,[&#x27;as&#x27;=&gt;&#x27;admin.logout&#x27;]);        &#125;);        $routes-&gt;group(&#x27;&#x27;,[],static function($routes)&#123;            // $routes-&gt;view(&#x27;example-auth&#x27;,&#x27;example-auth&#x27;);            $routes-&gt;get(&#x27;login&#x27;,&#x27;AuthController::loginForm&#x27;,[&#x27;as&#x27;=&gt;&#x27;admin.login.form&#x27;]);            $routes-&gt;post(&#x27;login&#x27;,&#x27;AuthController::loginHandler&#x27;,[&#x27;as&#x27;=&gt;&#x27;admin.login.handler&#x27;]);        &#125;);&#125;);

3. Validation是用$this-&gt;validate()方法去验证log_id 。rules为验证的规则，一般采用系统默认的一些规则。其中要注意的是is_not_unique,这个方法的参数是table.column,可以直接去数据库进行查询是否存在。
public function loginHandler()   &#123;       $fieldType = filter_var($this-&gt;request-&gt;getVar(&#x27;login_id&#x27;), FILTER_VALIDATE_EMAIL) ? &#x27;email&#x27; : &#x27;username&#x27;;       if ($fieldType == &#x27;email&#x27;) &#123;           //is_not_unique[table.column]是直接验证字段在表内的存在           $isValid = $this-&gt;validate([               &#x27;login_id&#x27; =&gt; [                   &#x27;rules&#x27; =&gt; &#x27;required|valid_email|is_not_unique[users.email]&#x27;,                   &#x27;errors&#x27; =&gt; [                       &#x27;required&#x27; =&gt; &#x27;Email is required&#x27;,                       &#x27;valid_email&#x27; =&gt; &#x27;Email is not valid&#x27;,                       &#x27;is_not_unique&#x27; =&gt; &#x27;Email is not exists in our system.&#x27;                   ]               ],               &#x27;password&#x27; =&gt; [                   &#x27;rules&#x27; =&gt; &#x27;required|min_length[5]|max_length[45]&#x27;,                   &#x27;errors&#x27; =&gt; [                       &#x27;required&#x27; =&gt; &#x27;password is required&#x27;,                       &#x27;min_length&#x27; =&gt; &#x27;min_length is 5&#x27;,                       &#x27;max_length&#x27; =&gt; &#x27;max_length is 45.&#x27;                   ]               ]           ]);       &#125; else &#123;           $isValid = $this-&gt;validate([               &#x27;login_id&#x27; =&gt; [                   &#x27;rules&#x27; =&gt; &#x27;required|is_not_unique[users.username]&#x27;,                   &#x27;errors&#x27; =&gt; [                       &#x27;required&#x27; =&gt; &#x27;username is required&#x27;,                       &#x27;is_not_unique&#x27; =&gt; &#x27;username is not exists in our system.&#x27;                   ]               ],               &#x27;password&#x27; =&gt; [                   &#x27;rules&#x27; =&gt; &#x27;required|min_length[5]|max_length[45]&#x27;,                   &#x27;errors&#x27; =&gt; [                       &#x27;required&#x27; =&gt; &#x27;password is required&#x27;,                       &#x27;min_length&#x27; =&gt; &#x27;min_length is 5&#x27;,                       &#x27;max_length&#x27; =&gt; &#x27;max_length is 45.&#x27;                   ]               ]           ]);       &#125;


4. 界面传参在示例文件中，将view界面创建了一个validation实例。&lt;?php $validation = \Config\Services::validation(); ?&gt; 。而将控制器里面的实例$this-&gt;validator()传给了view界面的$validation。使用geterror()获取对应的验证信息。
&lt;?php if ($validation-&gt;getError(&#x27;login_id&#x27;)) : ?&gt;            &lt;div class=&quot;d-block text-danger&quot; style=&quot;margin-top:-25px; margin-bottom:15px&quot;&gt;                &lt;?= $validation-&gt;getError(&#x27;login_id&#x27;); ?&gt;            &lt;/div&gt; &lt;?php endif; ?&gt;


CodeIgniter设计登出直接调用function移除session里面的相关数据。
public static function forget()&#123;    $session = session();    $session-&gt;remove(&#x27;logged_in&#x27;);    $session-&gt;remove(&#x27;userdata&#x27;);&#125;

CI框架请求的处理逻辑与步骤跟着视频学了好几个请求的处理，比如登录，忘记密码，重置密码等。大致思考一下这种框架的通用逻辑，方便后面再写的时候比对。
请求进入路由先要维护对应的Routes.php文件，比如下面这一串请求。设置对应的get&#x2F;post方法，
$routes-&gt;group(&#x27;&#x27;, [&#x27;filter&#x27; =&gt; &#x27;cifilter:guest&#x27;], static function ($routes) &#123;       // $routes-&gt;view(&#x27;example-auth&#x27;,&#x27;example-auth&#x27;);       $routes-&gt;get(&#x27;login&#x27;, &#x27;AuthController::loginForm&#x27;, [&#x27;as&#x27; =&gt; &#x27;admin.login.form&#x27;]);       $routes-&gt;post(&#x27;login&#x27;, &#x27;AuthController::loginHandler&#x27;, [&#x27;as&#x27; =&gt; &#x27;admin.login.handler&#x27;]);       $routes-&gt;get(&#x27;forgot-password&#x27;, &#x27;AuthController::forgotForm&#x27;, [&#x27;as&#x27; =&gt; &#x27;admin.forgot.form&#x27;]);       $routes-&gt;post(&#x27;send-password-reset-link&#x27;, &#x27;AuthController::sendPasswordResetLink&#x27;, [&#x27;as&#x27; =&gt; &#x27;send-password-reset-link&#x27;]);       $routes-&gt;get(&#x27;password/reset/(:any)&#x27;, &#x27;AuthController::resetPassword/$1&#x27;, [&#x27;as&#x27; =&gt; &#x27;admin.reset-password&#x27;]);       $routes-&gt;post(&#x27;reset-password-handler/(:any)&#x27;, &#x27;AuthController::resetPasswordHandler/$1&#x27;, [&#x27;as&#x27; =&gt; &#x27;reset-password-handler&#x27;]);   &#125;);
第一个参数是url的访问路径，第二个对应控制器的相应方法，as方法可以将routes 命名一个简单命令，这样在其他地方可以直接引用。例如在view中引用    &lt;form action=&quot;&lt;?= route_to(&#39;send-password-reset-link&#39;);?&gt;&quot; method=&quot;POST&quot;&gt;在参数里可以设置对应的filter 在/Config/Filter.php进行注册 
public array $aliases = [    &#x27;csrf&#x27;          =&gt; CSRF::class,    &#x27;toolbar&#x27;       =&gt; DebugToolbar::class,    &#x27;honeypot&#x27;      =&gt; Honeypot::class,    &#x27;invalidchars&#x27;  =&gt; InvalidChars::class,    &#x27;secureheaders&#x27; =&gt; SecureHeaders::class,    &#x27;cifilter&#x27;      =&gt; CIFilter::class,    ];


路由转入控制器建立相应的控制器以及方法，同时进行相应的逻辑判定。 

在控制器里面，需要注意可以加载相应的helper 类供后面使用。protected $helpers = [&#39;url&#39;, &#39;form&#39;, &#39;CIMail&#39;]; 例如，加载url, form和CIMail这个helper类，其中CIMail为自己创建的文件。
在控制器里面，可以使用validate方法，但是如果有自己创建的类，需要在/Config/Validation.php里面注册相应的类。public array $ruleSets = [    Rules::class,    FormatRules::class,    FileRules::class,    CreditCardRules::class,    IsPasswordStrong::class,];
之后再function里面就可以调用IsPasswordStrong$isValid = $this-&gt;validate([    &#x27;new_password&#x27; =&gt; [        &#x27;rules&#x27; =&gt; &#x27;required|min_length[5]|max_length[20]|is_password_strong[new_password]&#x27;,        &#x27;errors&#x27; =&gt; [            &#x27;required&#x27; =&gt; &#x27;Enter new password&#x27;,            &#x27;min_length&#x27; =&gt; &#x27;New password must have at least 5 characters&#x27;,            &#x27;max_length&#x27; =&gt; &#x27;New password must have at most 20 characters&#x27;,            &#x27;is_password_strong&#x27; =&gt; &#x27;new password is not strong enough&#x27;,        ]    ],    &#x27;confirm_new_password&#x27; =&gt; [        &#x27;rules&#x27; =&gt; &#x27;required|matches[new_password]&#x27;,        &#x27;errors&#x27; =&gt; [            &#x27;required&#x27; =&gt; &#x27;Confirm new password&#x27;,            &#x27;matches&#x27; =&gt; &#x27;Passwords not match&#x27;,        ]    ]]);

控制器进行跳转View常用的返回跳转有。

直接返回view界面 并且附带数据。public function loginForm()&#123;    $data = [        &#x27;pageTitle&#x27; =&gt; &#x27;Login&#x27;,        &#x27;validation&#x27; =&gt; null    ];    return view(&#x27;backend/pages/auth/login&#x27;, $data);&#125;
返回跳转到指定的route.使用这个方法可以跳转到admin.forot.form路由并附带一个success信息return redirect()-&gt;route(&#x27;admin.forgot.form&#x27;)-&gt;with(&#x27;success&#x27;, &#x27;We have email your password reset link&#x27;)
返回上一个界面返回上一个界面并且将之前的输入信息返回，同时附带fail提示信息 return redirect()-&gt;back()-&gt;with(&#x27;fail&#x27;,&#x27;Something went wrong!&#x27;)-&gt;withInput();

View界面展示
附带flash data的展示
&lt;?php if (!empty(session()-&gt;getFlashdata(&#x27;fail&#x27;))) : ?&gt;    &lt;div class=&quot;alert alert-danger&quot;&gt;        &lt;?= session()-&gt;getFlashdata(&#x27;fail&#x27;); ?&gt;        &lt;button type=&quot;button&quot; class=&quot;close&quot; data-dismiss=&quot;alert&quot; aria-label=&quot;close&quot;&gt;            &lt;span aria-hidden=&quot;true&quot;&gt;&amp;times;&lt;/span&gt;        &lt;/button&gt;    &lt;/div&gt;&lt;?php endif; ?&gt;

传入变量的引用。


//控制器传入View 的数据 &lt;?php   $data = [        &#x27;pageTitle&#x27; =&gt; &#x27;Login&#x27;,        &#x27;validation&#x27; =&gt; null    ]; ?&gt;//view 界面引用数据中的值 &lt;title&gt;&lt;?= isset($pageTitle) ? $pageTitle : &quot;New Page Title&quot;; ?&gt;&lt;/title&gt;


Validation部分的引用在view里面设置了validation变量，再从控制器的方法中传入validator, 在view界面进行error读取。


controller里面的设置&lt;?php         return view(&#x27;backend/pages/auth/login&#x27;, [             &#x27;pageTitle&#x27; =&gt; &#x27;Login&#x27;,             &#x27;validation&#x27; =&gt; $this-&gt;validator,         ]); ?&gt;
View界面的读取验证错误结果//先初始化一个validation&lt;?php $validation = \Config\Services::validation(); ?&gt;        &lt;?php if ($validation-&gt;getError(&#x27;login_id&#x27;)) : ?&gt;            &lt;div class=&quot;d-block text-danger&quot; style=&quot;margin-top:-25px; margin-bottom:15px&quot;&gt;                &lt;?= $validation-&gt;getError(&#x27;login_id&#x27;); ?&gt;            &lt;/div&gt;        &lt;?php endif; ?&gt;

总结透过这段逻辑就实现了从请求到路由到控制器再到view展示的步骤。对于MVC来说，model部分是和controller里面进行交互处理。所以并未特别备注。后面再研究一下model的交互。
